import axios from 'axios';

const api = {
  url: 'https://api.example.com',
};

async function request({
  method,
  endpoint,
  data = null,
  methodType,
  params = {},
}) {
  try {
    const response = await axios({
      baseURL: methodType === 'local' ? 'http://' : '',
      url: `${api.url}${endpoint}`,
      method,
      data,
      params,
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer YOUR_API_KEY', // replace with your api key
      },
    });

    return response.data;
  } catch (error) {
    console.error(error);
  }
}

const get = async (endpoint, params = {}, methodType) => {
  const { data } = await request({
    method: 'GET',
    endpoint,
    params,
    methodType,
  });
  
  return data;
};

const post = async (endpoint, data, methodType) => {
  const { data: response } = await request({
    method: 'POST',
    endpoint,
    data,
    methodType,
  });

  return response;
};

export { get, post };